export const parseRawServerSelectOptionValue = (value, option) => {
    if (typeof value !== 'string')
        return;
    return option.values[value] ? value : undefined;
};
export const normalizeServerSelectOptionValue = (value, option) => value ?? option.def;
export const serializeServerSelectOptionValue = (value) => value;
export const toServerSelectOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    def: option.def,
    values: Object.entries(option.values).map(([name, title]) => ({
        name,
        title: localize(title),
    })),
});
